public static void Max(ref int target, int value)
{
    int snapshot;
    do
    {
        snapshot = Volatile.Read(ref target);
        if (value <= snapshot) return;
    }
    while (Interlocked.CompareExchange(ref target, value, snapshot) != snapshot);
}

private readonly ConcurrentDictionary<string, int> _hits = new();
public void Record(string key)
{
    if (_hits.ContainsKey(key))
        _hits[key] = _hits[key] + 1;
    else
        _hits[key] = 1;
}

